/// <summary>
/// event handler class for form <c>ETGITMTableListPageOutbound</c>
/// </summary>
internal final class ETGITMTableListPageEventHandler
{
}

Method.Source:
/// <summary>
/// throw error if landed cost module for outbound orders is not enabled for this legal entity
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormEventHandler(formStr(ETGITMTableListPageOutbound), FormEventType::Initializing)]
public static void ETGITMTableListPageOutbound_OnInitializing(xFormRun sender, FormEventArgs e)
{
    if(ITMParameters::find().ETGEnableLandedCostOutboundOrder == NoYes::No)
    {
        throw Error("@ETG_New:LandedCostModuleNotEnabled");
    }
}
